// Batch 6: Bosnia, Botswana, Brunei
module.exports = {
'Bosnia': [
  { title: 'Burek Bosnia', summary: 'Bosnian coiled phyllo pie stuffed with seasoned ground beef', description: 'Bosnian Burek is a spiral-coiled pie of hand-stretched dough layered with seasoned ground beef and onions, baked until flaky and golden.', ingredients: ['500g ground beef','2 large onions, finely diced','1 tsp salt','1 tsp black pepper','1/2 tsp paprika','1 package phyllo dough (or hand-stretched jufka)','1/2 cup vegetable oil','1/2 cup warm water','plain yogurt for serving'], instructions: ['Mix ground beef with onions, salt, pepper and paprika.','Lay out sheets of phyllo, brush with oil.','Spread a thin line of meat filling along one edge.','Roll into a long thin tube, then coil into a snail shape in a round baking pan.','Continue with remaining dough and filling, coiling around the center.','Brush top with oil, splash warm water over it.','Bake at 200°C (400°F) for 40 minutes until golden and flaky.','Serve hot with cold plain yogurt.'], prepTime: 30, cookTime: 40, servings: 6, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/B%C3%B6rek' },
  { title: 'Bosanski Lonac', summary: 'Bosnian layered meat and vegetable pot', description: 'Bosanski Lonac is a traditional layered stew — chunks of various meats alternated with layers of vegetables, slow-cooked in a clay pot with minimal liquid.', ingredients: ['300g beef, cubed','300g lamb, cubed','200g cabbage, chopped','2 potatoes, cubed','2 carrots, sliced','2 tomatoes, sliced','1 onion, sliced','1 bell pepper, sliced','4 cloves garlic','1 tsp black peppercorns','2 bay leaves','1/2 cup white wine','1 cup water','salt','fresh parsley'], instructions: ['In a large clay pot or Dutch oven, layer: cabbage, beef, onion, potato, lamb, carrot, tomato, pepper.','Tuck garlic, bay leaves and peppercorns between layers, season each layer with salt.','Pour wine and water over the top.','Cover tightly, bake at 160°C (325°F) for 3-4 hours.','Do not stir — the layers slowly meld and the meats become meltingly tender.','Serve directly from the pot, garnished with parsley.'], prepTime: 20, cookTime: 240, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Bosanski_lonac' },
  { title: 'Ćevapi Bosnia', summary: 'Bosnian grilled minced meat sausages in somun bread', description: 'Ćevapi are iconic Bosnian finger-shaped grilled sausages of mixed beef and lamb, served in somun flatbread with raw onions and kajmak cream.', ingredients: ['500g ground beef','250g ground lamb','1/2 tsp baking soda','3 cloves garlic, minced','1 tsp salt','1/2 tsp black pepper','somun or pita bread','1 white onion, diced raw','kajmak or sour cream','ajvar (red pepper spread)'], instructions: ['Mix beef and lamb with baking soda, garlic, salt and pepper.','Knead well for 5 minutes, refrigerate for at least 2 hours (overnight best).','Shape into finger-sized sausages about 3 inches long.','Grill over very hot charcoal, turning frequently, 6-8 minutes until charred outside, juicy inside.','Open somun bread, stuff with 8-10 ćevapi.','Top with raw diced onion and a generous spoonful of kajmak.','Serve with ajvar on the side.'], prepTime: 140, cookTime: 8, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/%C4%86evapi' },
  { title: 'Begova Čorba', summary: 'Bosnian creamy chicken and okra soup', description: 'Begova Čorba (Bey\'s soup) is an elegant Bosnian soup of chicken, okra and vegetables enriched with a roux and finished with sour cream.', ingredients: ['500g chicken breast','8 okra pods, sliced','1 carrot, diced','1 celery stalk, diced','1 onion, diced','2 tbsp butter','2 tbsp flour','1/2 cup sour cream','6 cups chicken broth','1 tbsp lemon juice','salt and pepper','fresh parsley'], instructions: ['Poach chicken in broth until cooked, shred into pieces.','Sauté onion, carrot and celery in butter until soft.','Add flour, stir to make a roux, cook 2 minutes.','Gradually add broth, stirring until smooth.','Add okra and shredded chicken, simmer 20 minutes.','Mix sour cream with lemon juice, stir into the soup off heat.','Season with salt and pepper, garnish with parsley.'], prepTime: 15, cookTime: 40, servings: 4, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Begova_%C4%8Dorba' },
  { title: 'Dolma Bosnia', summary: 'Bosnian stuffed vegetables with meat and rice filling', description: 'Bosnian Dolma refers to various vegetables — peppers, onions, zucchini, grape leaves — stuffed with a seasoned rice and meat filling, baked in tomato sauce.', ingredients: ['6 bell peppers or mixed vegetables','400g ground beef','1 cup rice','1 onion, diced','2 tbsp fresh parsley','1 tsp paprika','1/2 tsp black pepper','salt','1 cup tomato passata','1 cup water','2 tbsp oil'], instructions: ['Mix ground beef, rice, onion, parsley, paprika, pepper and salt.','Hollow out peppers (or prepare vegetables for stuffing).','Stuff each vegetable with the meat-rice mixture.','Arrange in a baking dish.','Mix passata with water and oil, pour around the stuffed vegetables.','Cover with foil, bake at 180°C (350°F) for 50 minutes.','Remove foil, bake 15 more minutes until vegetables are soft and tops browned.'], prepTime: 20, cookTime: 65, servings: 6, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Dolma' },
  { title: 'Klepe', summary: 'Bosnian meat dumplings in garlic yogurt sauce', description: 'Klepe are Bosnian dumplings filled with ground meat and onion, boiled and served in a garlic yogurt sauce — similar to Turkish manti.', ingredients: ['2 cups flour','1/2 cup water','1 egg','salt','For filling: 300g ground beef','1 onion, finely diced','salt and pepper','For sauce: 1 cup yogurt','2 cloves garlic, minced','2 tbsp butter','1 tsp paprika'], instructions: ['Make dough with flour, water, egg and salt, knead smooth, rest 30 min.','Mix beef, onion, salt and pepper.','Roll dough thin, cut 2-inch squares. Place filling in each, fold into triangles and seal.','Boil dumplings in salted water 10-12 minutes until they float.','Mix yogurt with garlic and salt.','Melt butter, stir in paprika.','Drain dumplings, arrange on plate, pour yogurt sauce over, drizzle paprika butter.'], prepTime: 40, cookTime: 15, servings: 4, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Manti_(food)' },
  { title: 'Pita Zeljanica', summary: 'Bosnian spinach and cheese phyllo pie', description: 'Zeljanica is a Bosnian savory pie of thin stretched dough layered with a filling of spinach, feta cheese and eggs, baked until golden and crispy.', ingredients: ['500g fresh spinach, chopped','300g feta cheese, crumbled','3 eggs','1 package phyllo dough','1/4 cup oil','1/4 cup yogurt','salt and pepper'], instructions: ['Wilt spinach, squeeze out all water, chop finely.','Mix spinach with feta, eggs, yogurt, salt and pepper.','Layer phyllo sheets in a round pan, brushing each with oil.','Spread spinach filling, then more phyllo, more filling.','Top with final phyllo layers, brush with oil.','Bake at 190°C (375°F) for 35-40 minutes until golden.','Let rest 10 minutes, cut into squares.'], prepTime: 20, cookTime: 40, servings: 6, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/B%C3%B6rek' },
  { title: 'Hurmasice', summary: 'Bosnian semolina cookies soaked in sweet syrup', description: 'Hurmasice are soft Bosnian semolina cookies shaped like dates, baked until lightly golden then soaked in a lemony sugar syrup until they puff and become moist.', ingredients: ['2 cups semolina','1 cup plain yogurt','1/2 cup sugar','1 egg','1/2 tsp baking soda','For syrup: 2 cups sugar','1.5 cups water','juice of 1/2 lemon','1 tsp vanilla'], instructions: ['Make syrup: boil sugar and water 10 minutes, add lemon juice and vanilla, cool.','Mix semolina, yogurt, sugar, egg and baking soda into a soft dough.','Shape into small date-sized ovals.','Place on a lined baking sheet.','Bake at 180°C (350°F) for 15-18 minutes until just lightly golden.','While hot, pour cold syrup over the cookies.','Let them soak for several hours — they will puff up and become spongy.'], prepTime: 15, cookTime: 18, servings: 12, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Hurmasice' },
  { title: 'Tufahije', summary: 'Bosnian poached apples stuffed with walnuts in syrup', description: 'Tufahije are a classic Bosnian dessert — whole apples poached in sugar syrup, cored and filled with a walnut mixture, served chilled with whipped cream.', ingredients: ['6 medium apples, peeled and cored','2 cups sugar','4 cups water','juice of 1 lemon','1 cup walnuts, finely chopped','2 tbsp sugar for walnut mix','whipped cream for serving'], instructions: ['Make syrup: dissolve 2 cups sugar in water with lemon juice, bring to boil.','Add peeled, cored apples. Simmer gently 15-20 minutes until tender but not mushy.','Remove apples, continue simmering syrup until slightly thick.','Mix walnuts with 2 tbsp sugar, stuff into the center of each apple.','Place stuffed apples in a serving dish, pour syrup over.','Chill for several hours.','Serve cold topped with whipped cream.'], prepTime: 15, cookTime: 25, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Tufahije' },
  { title: 'Mantije', summary: 'Bosnian baked meat-filled rolls in a spiral pan', description: 'Mantije are small Bosnian baked dumplings filled with ground beef, arranged snugly in a round pan and baked until golden — served with yogurt.', ingredients: ['3 cups flour','1 cup warm water','1 tsp salt','1 tbsp oil','500g ground beef','1 onion, diced','salt, pepper, paprika','1 cup yogurt for serving'], instructions: ['Make dough: flour, water, salt, oil. Knead, rest 30 minutes.','Cook beef with onion, season with salt, pepper and paprika. Cool.','Divide dough into small balls, flatten each, fill with meat, pinch closed.','Arrange seam-down tightly in a round greased pan.','Bake at 200°C (400°F) for 30-35 minutes until tops are golden.','Serve hot with cold yogurt poured over.'], prepTime: 30, cookTime: 35, servings: 6, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Bosnian_cuisine' },
  { title: 'Podvarak Bosnia', summary: 'Bosnian baked sauerkraut with smoked meat', description: 'Podvarak is a hearty Bosnian dish of sauerkraut baked with smoked meat and onions — slow-cooked until the sauerkraut is meltingly soft and caramelized.', ingredients: ['1 kg sauerkraut, drained','500g smoked pork ribs or sausage','2 onions, sliced','3 tbsp lard or oil','1 tsp paprika','1 tsp sugar','1/2 cup water','bay leaf'], instructions: ['Rinse sauerkraut if very sour, squeeze dry.','Fry onions in lard until golden, add paprika.','Layer sauerkraut and smoked meat in a baking dish with the onions.','Add bay leaf, sugar and water.','Cover and bake at 180°C (350°F) for 1.5-2 hours until very tender.','Uncover last 20 minutes to brown the top.','Serve hot with bread.'], prepTime: 10, cookTime: 120, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Podvarak' },
  { title: 'Kiflice', summary: 'Bosnian crescent-shaped cheese rolls', description: 'Kiflice are soft crescent-shaped Bosnian rolls filled with white cheese (feta) — light, fluffy and perfect for breakfast or snacking.', ingredients: ['3 cups flour','1 packet yeast','1 cup warm milk','1/4 cup oil','1 tsp sugar','1 tsp salt','200g feta cheese, crumbled','1 egg yolk for glaze','sesame seeds'], instructions: ['Dissolve yeast and sugar in warm milk.','Mix flour, salt, add yeast mixture and oil. Knead soft dough, rise 1 hour.','Roll dough into a circle, cut into triangles like pizza slices.','Place a spoonful of feta at the wide end, roll toward the point, curve into a crescent.','Place on a baking sheet, brush with egg yolk, sprinkle sesame seeds.','Let rise 20 minutes.','Bake at 190°C (375°F) for 15-18 minutes until golden.'], prepTime: 90, cookTime: 18, servings: 12, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Kifli' },
  { title: 'Baklava Bosnia', summary: 'Bosnian layered nut pastry in sugar syrup', description: 'Bosnian Baklava features layers of phyllo dough filled with ground walnuts and spices, baked until crispy and drenched in a lemony sugar syrup.', ingredients: ['500g phyllo pastry','2 cups walnuts, ground','1/2 cup sugar','1 tsp cinnamon','1/2 tsp cloves','1 cup butter, melted','For syrup: 2 cups sugar','1.5 cups water','juice of 1 lemon'], instructions: ['Make syrup: boil sugar and water 10 min, add lemon juice, cool completely.','Mix walnuts, sugar, cinnamon and cloves.','Layer 5-6 phyllo sheets in a buttered pan, brushing each with butter.','Spread a thin layer of walnut mixture.','Repeat: 2 sheets + butter + walnuts, until filling is gone.','Top with 5-6 sheets, brush generously.','Cut into diamond shapes.','Bake at 170°C (340°F) for 40-45 minutes until golden.','Pour cold syrup over hot baklava. Let soak several hours.'], prepTime: 30, cookTime: 45, servings: 12, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Baklava' },
  { title: 'Uštipci', summary: 'Bosnian fried dough puffs served with kajmak', description: 'Uštipci are small Bosnian fried dough balls — golden, puffy and light, served for breakfast with kajmak (clotted cream), jam or cheese.', ingredients: ['2 cups flour','1 cup warm milk','1 packet yeast','1 tsp sugar','1/2 tsp salt','1 egg','oil for deep frying','kajmak or jam for serving'], instructions: ['Dissolve yeast and sugar in warm milk.','Mix flour, salt, egg and yeast mixture into a soft batter.','Cover, let rise 1 hour until doubled and bubbly.','Heat oil to 175°C (350°F).','Drop spoonfuls of batter into hot oil, fry until golden on all sides, about 3 minutes.','Drain on paper towels.','Serve hot with kajmak, honey or jam.'], prepTime: 70, cookTime: 15, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/U%C5%A1tipci' },
  { title: 'Pilav Bosnia', summary: 'Bosnian buttery rice pilaf', description: 'Bosnian Pilav is a simple, buttery rice dish cooked with vermicelli noodles and chicken broth — the standard side dish for Bosnian meat courses.', ingredients: ['2 cups long-grain rice','1/4 cup vermicelli noodles, broken','3 tbsp butter','3 cups chicken broth','1 tsp salt'], instructions: ['Toast vermicelli in butter until golden.','Add rice, stir to coat in butter.','Add broth and salt, bring to a boil.','Reduce heat to lowest, cover tightly.','Cook 18 minutes until liquid absorbed.','Rest covered 10 minutes, fluff with fork.'], prepTime: 5, cookTime: 25, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Pilaf' },
  { title: 'Sogan Dolma Bosnia', summary: 'Bosnian whole onions stuffed with meat and rice', description: 'Sogan Dolma features large onions hollowed out and stuffed with a savory mixture of ground meat and rice, simmered in tomato sauce until meltingly tender.', ingredients: ['6 large onions','300g ground beef','1/2 cup rice','1 tsp paprika','1/2 tsp black pepper','salt','1 cup tomato passata','1 cup water','2 tbsp oil'], instructions: ['Boil whole onions 5 minutes, drain and cool.','Cut off tops, carefully push out inner layers leaving 2-3 outer layers as shells.','Dice the removed onion centers.','Mix beef, rice, diced onion, paprika, pepper and salt.','Stuff each onion shell, replace tops.','Arrange in a pot, pour passata mixed with water and oil around them.','Cover, simmer 1 hour until onions are very soft and rice is cooked.'], prepTime: 25, cookTime: 65, servings: 6, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Dolma' },
  { title: 'Sirnica', summary: 'Bosnian phyllo cheese pie spiral', description: 'Sirnica is a Bosnian cheese pie made with stretched dough and a filling of cottage cheese and eggs, coiled into a round pan and baked.', ingredients: ['1 package phyllo dough','400g cottage cheese','200g feta cheese, crumbled','3 eggs','1/4 cup oil','salt'], instructions: ['Mix cottage cheese, feta, eggs and salt.','Lay out phyllo sheets, brush with oil.','Spread cheese filling in a line along one edge.','Roll into a tube, then coil into a round greased pan.','Repeat with remaining dough and filling.','Brush top with oil.','Bake at 190°C (375°F) for 35 minutes until golden.','Serve warm or at room temperature.'], prepTime: 15, cookTime: 35, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/B%C3%B6rek' },
  { title: 'Kompot Bosnia', summary: 'Bosnian fruit compote drink of stewed seasonal fruits', description: 'Kompot is a Bosnian beverage and dessert — seasonal fruits gently stewed in sugar syrup, served chilled as a refreshing drink with the fruits.', ingredients: ['3 cups mixed fruits (apples, pears, plums, cherries)','1 cup sugar','6 cups water','1 cinnamon stick','2 cloves'], instructions: ['Bring water and sugar to a boil.','Add cinnamon and cloves.','Add prepared fruits (peeled, halved or quartered).','Simmer 15-20 minutes until fruit is tender but holds shape.','Cool to room temperature, then chill.','Serve cold in glasses with fruit pieces.'], prepTime: 10, cookTime: 20, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Compote' },
  { title: 'Jagnjetina Ispod Sača', summary: 'Bosnian whole lamb slow-roasted under a domed lid', description: 'Jagnjetina Ispod Sača is lamb and vegetables slow-cooked under a sač — a heavy domed metal lid covered with hot coals, creating a primitive oven.', ingredients: ['2 kg lamb shoulder or leg, bone-in','1 kg potatoes, quartered','2 onions, quartered','4 tomatoes, halved','2 bell peppers, quartered','1 head garlic, halved','1/4 cup olive oil','1 cup white wine','1 tsp rosemary','salt and pepper'], instructions: ['Season lamb with salt, pepper and rosemary.','Place lamb in a large pot or baking dish, surround with vegetables and garlic.','Drizzle with oil and wine.','Cover with a sač (dome lid) and pile hot coals on top. Or cover tightly with foil in an oven.','Cook at 160°C (325°F) for 3-4 hours until lamb is falling off the bone.','Serve directly from the pot with the roasted vegetables.'], prepTime: 15, cookTime: 240, servings: 8, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Bosnian_cuisine' },
  { title: 'Đuveč Bosnia', summary: 'Bosnian baked mixed vegetable and rice casserole', description: 'Đuveč is a Bosnian vegetable casserole of rice, peppers, tomatoes, eggplant and zucchini baked together with paprika and oil into a comforting one-dish meal.', ingredients: ['1 cup rice','2 bell peppers, diced','2 tomatoes, diced','1 eggplant, diced','1 zucchini, diced','1 onion, diced','3 cloves garlic, minced','1/4 cup olive oil','1 tbsp paprika','1 tsp salt','2 cups broth'], instructions: ['Sauté onion and garlic in oil, add paprika.','Add all vegetables, cook 5 minutes.','Stir in rice and broth.','Transfer to a baking dish, cover.','Bake at 190°C (375°F) for 40 minutes until rice is tender.','Uncover last 10 minutes to brown top.','Serve as a vegetarian main or side dish.'], prepTime: 15, cookTime: 45, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/%C4%90uve%C4%8D' },
],
'Botswana': [
  { title: 'Seswaa', summary: 'Botswana\'s national dish of slow-pounded shredded beef', description: 'Seswaa is Botswana\'s most beloved dish — beef or goat meat boiled with just salt until falling apart, then pounded and shredded with a fork, served with pap.', ingredients: ['1 kg beef chuck or brisket, bone-in','1 large onion, quartered','1 tbsp salt','water to cover'], instructions: ['Place beef in a large pot with onion and salt, cover with water.','Bring to a boil, reduce to a simmer.','Cook for 3-4 hours until meat is extremely tender and falling off the bone.','Remove bones.','Using two forks or a mortar, pound and shred the meat until finely pulled.','Mix some of the cooking broth back in to keep it moist.','Serve with bogobe (porridge) or pap.'], prepTime: 5, cookTime: 240, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Seswaa' },
  { title: 'Bogobe', summary: 'Botswana sorghum or maize porridge', description: 'Bogobe is Botswana\'s everyday starchy staple — thick porridge made from sorghum, millet or maize meal, cooked until stiff and smooth, the base of every meal.', ingredients: ['2 cups sorghum flour or maize meal','4 cups water','1 tsp salt','1 tbsp butter (optional)'], instructions: ['Bring 3 cups water to a boil with salt.','Mix flour with remaining cold water to make a smooth paste.','Pour paste into boiling water, stirring vigorously.','Cook on medium-low heat, stirring constantly for 15-20 minutes.','The porridge should be very thick, pulling from the sides of the pot.','Stir in butter if using, shape into a mound.','Serve with seswaa, morogo or any stew.'], prepTime: 5, cookTime: 25, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Bogobe' },
  { title: 'Morogo', summary: 'Botswana wild spinach cooked with onion and tomato', description: 'Morogo is a Botswana dish of indigenous wild greens sautéed with onion, tomato and a touch of peanut butter — packed with nutrients.', ingredients: ['500g wild spinach or Swiss chard, chopped','1 onion, diced','2 tomatoes, diced','1 tbsp peanut butter','1 tbsp vegetable oil','salt and pepper'], instructions: ['Heat oil, sauté onion until soft.','Add tomatoes, cook until softened.','Add chopped greens, stir.','Cover and cook 10 minutes until wilted.','Stir in peanut butter, mix well.','Season with salt and pepper, serve as a side.'], prepTime: 10, cookTime: 15, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Morogo' },
  { title: 'Madila', summary: 'Botswana fermented milk similar to thick buttermilk', description: 'Madila is traditional Botswana fermented milk — whole cow\'s milk left to sour naturally, resulting in a thick, tangy drink rich in probiotics.', ingredients: ['2 liters whole milk (unpasteurized preferred)','1 tbsp of previous madila culture (or buttermilk)'], instructions: ['Pour milk into a clean calabash, clay pot or glass container.','Add a spoonful of previous madila or buttermilk as starter.','Cover loosely, let sit at room temperature for 24-48 hours.','The milk will thicken and sour.','Stir or shake before serving.','Drink on its own or serve with bogobe.'], prepTime: 5, cookTime: 0, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Botswana_cuisine' },
  { title: 'Ting Porridge', summary: 'Botswana fermented sorghum porridge', description: 'Ting is a Botswana sour porridge made from fermented sorghum — it has a distinctive tangy flavor and is served both as a thin drink and a thick staple.', ingredients: ['2 cups sorghum flour','4 cups water','1/2 tsp salt','sugar or milk (optional)'], instructions: ['Mix sorghum flour with 2 cups water, cover and leave to ferment at room temperature for 1-2 days until sour.','Bring remaining water to a boil.','Gradually stir in the fermented mixture.','Cook on low heat, stirring for 15-20 minutes until thick.','For thin ting (drink): add more water and sugar.','For thick ting (staple): cook until stiff.','Serve with milk and sugar for breakfast, or plain with stews for dinner.'], prepTime: 10, cookTime: 20, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Ting_(food)' },
  { title: 'Magwinya Fritters', summary: 'Botswana fried dough puffs sold as street food', description: 'Magwinya (also called fat cakes) are puffy, golden fried dough balls — Botswana\'s favorite street food, eaten plain, with butter, or stuffed with mince.', ingredients: ['3 cups all-purpose flour','1 tsp dry yeast','2 tbsp sugar','1/2 tsp salt','1 cup warm water','oil for deep frying'], instructions: ['Mix flour, yeast, sugar and salt.','Add warm water, mix into a soft sticky dough.','Cover and let rise 1-2 hours until doubled.','Heat oil to 170°C (340°F).','Pull off golf-ball sized pieces, drop into hot oil.','Fry 3-4 minutes, turning, until golden and cooked through.','Drain on paper towels, serve warm plain or with butter and jam.'], prepTime: 80, cookTime: 15, servings: 8, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Vetkoek' },
  { title: 'Samp and Beans Botswana', summary: 'Botswana dried corn kernels cooked with sugar beans', description: 'Samp and Beans is a classic Southern African dish popular in Botswana — dried corn kernels and sugar beans slow-cooked together until tender and creamy.', ingredients: ['2 cups dried samp (hominy)','1 cup dried sugar beans','1 onion, diced','2 tbsp butter','salt and pepper','6 cups water'], instructions: ['Soak samp and beans separately overnight.','Boil samp in fresh water for 1.5 hours until starting to soften.','Add beans, cook together another 1 hour until both are tender.','Sauté onion in butter, add to the pot.','Season with salt and pepper, cook 10 more minutes.','Serve as a hearty side or main dish.'], prepTime: 15, cookTime: 160, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Samp' },
  { title: 'Mabele', summary: 'Botswana sorghum meal breakfast porridge', description: 'Mabele is a smooth Botswana breakfast porridge made from sorghum meal, cooked with milk and sugar — nutritious and filling.', ingredients: ['1 cup sorghum meal','3 cups milk','2 cups water','3 tbsp sugar','pinch of salt'], instructions: ['Mix sorghum meal with 1 cup cold water to make a smooth paste.','Boil remaining water with milk and salt.','Stir in the sorghum paste, reduce heat.','Cook on low, stirring frequently, 15-20 minutes until smooth and thick.','Sweeten with sugar, add more milk if desired.','Serve hot for breakfast.'], prepTime: 5, cookTime: 20, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Botswana_cuisine' },
  { title: 'Phane Stew', summary: 'Botswana mopane worm stew with tomato and onion', description: 'Phane (mopane worms) are a prized protein source in Botswana — dried caterpillars simmered with tomatoes, onion and spices into a savory stew.', ingredients: ['2 cups dried mopane worms (phane)','2 tomatoes, diced','1 onion, diced','2 cloves garlic, minced','1 green chili, sliced','2 tbsp vegetable oil','1 cup water','salt and pepper'], instructions: ['Soak dried mopane worms in warm water for 30 minutes, drain.','Heat oil, sauté onion and garlic until soft.','Add tomatoes and chili, cook 5 minutes.','Add mopane worms and water.','Simmer 20-30 minutes until worms are tender and sauce is thick.','Season with salt and pepper.','Serve with bogobe or rice.'], prepTime: 35, cookTime: 35, servings: 4, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Mopane_worm' },
  { title: 'Dikgobe', summary: 'Botswana beans, corn and melon seed stew', description: 'Dikgobe is a traditional Botswana dish combining beans, dried corn and ground melon seeds into a thick, protein-rich stew — an ancient staple recipe.', ingredients: ['1 cup dried cowpeas or beans, soaked','1 cup dried corn kernels, soaked','1/4 cup ground melon seeds (or peanut butter)','1 onion, diced','2 tbsp oil','salt','4 cups water'], instructions: ['Boil soaked corn for 1 hour until starting to soften.','Add soaked beans, cook another 1 hour until both are tender.','Sauté onion in oil, add to the pot.','Stir in ground melon seeds.','Cook 15 more minutes until thick.','Season with salt, serve hot.'], prepTime: 15, cookTime: 135, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Botswana_cuisine' },
  { title: 'Bogobe jwa Lerotse', summary: 'Botswana melon porridge', description: 'Bogobe jwa Lerotse is a unique Botswana porridge where sorghum or maize is cooked with lerotse melon, creating a naturally sweet, flavorful porridge.', ingredients: ['1 cup sorghum flour','1 medium lerotse (or butternut squash), peeled and cubed','3 cups water','1/2 tsp salt','sugar to taste'], instructions: ['Boil melon cubes in water until very soft, about 15 minutes.','Mash the melon in the cooking water.','Gradually stir in sorghum flour.','Cook on low heat, stirring for 15-20 minutes until thick.','Season with salt and sugar to taste.','Serve as a breakfast porridge or side.'], prepTime: 10, cookTime: 35, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Botswana_cuisine' },
  { title: 'Phane Salad', summary: 'Botswana mopane worm salad with tomato and onion', description: 'A lighter way to enjoy phane — dried mopane worms tossed with fresh tomatoes, onion and chili in a vinegar dressing, served as a crunchy salad.', ingredients: ['1 cup dried mopane worms, soaked and sautéed','2 tomatoes, diced','1 onion, sliced','1 green chili, sliced','2 tbsp vinegar','1 tbsp oil','salt and pepper','fresh cilantro'], instructions: ['Soak dried worms 30 minutes, drain.','Sauté in oil until slightly crispy.','Toss with diced tomatoes, onion and chili.','Dress with vinegar, salt and pepper.','Garnish with cilantro, serve as an appetizer.'], prepTime: 40, cookTime: 10, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Mopane_worm' },
  { title: 'Braised Goat Botswana', summary: 'Botswana slow-braised goat with onions', description: 'Braised goat is a common Botswana celebration dish — goat meat slowly braised with onions and water until very tender, seasoned simply with salt.', ingredients: ['1 kg goat meat, bone-in, cubed','2 onions, sliced','1 tbsp salt','4 cups water','1 tbsp oil'], instructions: ['Heat oil, brown goat pieces on all sides.','Add onions, cook until softened.','Add water and salt.','Cover and simmer on very low heat for 2-3 hours until meat is very tender.','The broth should reduce to a thick gravy.','Serve with bogobe or rice.'], prepTime: 10, cookTime: 180, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Botswana_cuisine' },
  { title: 'Mopane Worm Stew', summary: 'Botswana mopane caterpillars stewed with peanut sauce', description: 'A richer variation of phane stew — mopane worms cooked in a creamy peanut and tomato sauce, a delicacy in northern Botswana.', ingredients: ['2 cups dried mopane worms, soaked','2 tbsp peanut butter','2 tomatoes, diced','1 onion, diced','2 tbsp oil','1 chili pepper','1 cup water','salt'], instructions: ['Soak and drain mopane worms.','Sauté onion, add tomatoes and chili, cook 5 minutes.','Dissolve peanut butter in water, add to the pot.','Add mopane worms, simmer 25 minutes.','Season with salt, serve with pap.'], prepTime: 40, cookTime: 30, servings: 4, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Mopane_worm' },
  { title: 'Dried Meat Biltong Botswana', summary: 'Botswana air-dried spiced beef strips', description: 'Biltong is cured, air-dried meat popular in Botswana — beef strips seasoned with vinegar, salt, coriander and pepper, hung to dry into a savory snack.', ingredients: ['1 kg beef silverside, cut into long strips','1/2 cup brown vinegar','2 tbsp coarse salt','1 tbsp brown sugar','1 tbsp ground coriander','1 tsp ground black pepper','1/2 tsp ground allspice'], instructions: ['Dip beef strips in vinegar, shake off excess.','Mix salt, sugar, coriander, pepper and allspice.','Rub the spice mix all over the beef strips.','Layer in a glass dish, refrigerate overnight.','Hang strips in a well-ventilated, dry area (or use a biltong dryer).','Dry for 3-5 days until firm but still slightly soft inside.','Slice thinly against the grain to serve.'], prepTime: 20, cookTime: 0, servings: 8, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Biltong' },
  { title: 'Roasted Corn Botswana', summary: 'Street-style charcoal-roasted corn on the cob', description: 'Roasted corn is Botswana\'s simplest and most popular street food — fresh corn on the cob roasted over charcoal until smoky and slightly charred.', ingredients: ['4 ears fresh corn, husked','salt','butter (optional)'], instructions: ['Build a charcoal fire and let coals develop white ash.','Place corn directly on the grill grate.','Turn every few minutes for 10-15 minutes total until kernels are charred in spots.','Season with salt and rub with butter if desired.','Eat directly off the cob.'], prepTime: 2, cookTime: 15, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Botswana_cuisine' },
  { title: 'Chicken Stew Botswana', summary: 'Botswana simple chicken and vegetable stew', description: 'A staple Botswana chicken stew — chicken pieces simmered with onion, tomato and potato in a simple broth, everyday home cooking.', ingredients: ['1 whole chicken, cut into pieces','2 onions, diced','3 tomatoes, diced','3 potatoes, cubed','2 tbsp oil','4 cups water','salt and pepper'], instructions: ['Brown chicken in oil, remove.','Sauté onions until soft, add tomatoes, cook 5 minutes.','Return chicken, add water and potatoes.','Simmer 40-50 minutes until chicken is cooked and potatoes tender.','Season with salt and pepper.','Serve with rice or bogobe.'], prepTime: 10, cookTime: 55, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Botswana_cuisine' },
  { title: 'Mosako', summary: 'Botswana wild melon and pumpkin seed snack', description: 'Mosako is roasted and ground wild melon seeds — a traditional Botswana snack and cooking ingredient, rich in protein and healthy fats.', ingredients: ['2 cups wild melon seeds or pumpkin seeds','1 tsp salt'], instructions: ['Wash seeds, remove any pulp.','Spread on a baking sheet.','Roast at 160°C (325°F) for 15-20 minutes, stirring occasionally, until golden and fragrant.','Season with salt while hot.','Eat as a snack, or grind into powder to add to stews and porridges.'], prepTime: 10, cookTime: 20, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Botswana_cuisine' },
  { title: 'Ting Sour Porridge', summary: 'Botswana thin fermented sorghum drink', description: 'Thin Ting is the drinkable version of Botswana\'s fermented sorghum — served cold with sugar, it\'s a tangy, refreshing beverage.', ingredients: ['1 cup sorghum flour','4 cups water','sugar to taste','cold milk (optional)'], instructions: ['Mix sorghum flour with 1 cup water, let ferment covered for 1-2 days.','Boil remaining water, stir in fermented mixture.','Cook 10 minutes, stirring.','Cool to room temperature, then chill.','Thin with cold water or milk to drinkable consistency.','Sweeten with sugar, serve cold.'], prepTime: 10, cookTime: 10, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Ting_(food)' },
  { title: 'Sorghum Porridge Botswana', summary: 'Botswana traditional thick sorghum breakfast porridge', description: 'Simple sorghum porridge cooked with water and sweetened with sugar — the most common breakfast in rural Botswana.', ingredients: ['1 cup sorghum flour','3 cups water','salt','sugar','milk for serving'], instructions: ['Mix sorghum flour with 1 cup cold water into a paste.','Boil remaining water with a pinch of salt.','Stir paste into boiling water.','Cook 15-20 minutes on low, stirring often.','Serve with sugar and milk.'], prepTime: 5, cookTime: 20, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Botswana_cuisine' },
],
'Brunei': [
  { title: 'Ambuyat', summary: 'Brunei\'s national dish — starchy sago dip eaten with sauces', description: 'Ambuyat is a unique Bruneian dish of sago starch cooked into a translucent, sticky, glue-like dough, eaten by twirling on bamboo sticks and dipping into sour-spicy sauces.', ingredients: ['2 cups sago flour (from sago palm)','2 cups boiling water','For cacah sauce: 1 cup tamarind juice','2 tbsp shrimp paste','3 bird\'s eye chilies','1 clove garlic','salt'], instructions: ['Pour boiling water over sago flour in a bowl.','Stir vigorously with a fork or chopstick until it forms a sticky, translucent paste.','Make cacah sauce: blend tamarind juice, shrimp paste, chilies and garlic.','Serve the ambuyat in its bowl with the sauce alongside.','Eat by twirling ambuyat around a bamboo stick (candas) and dipping in sauce.'], prepTime: 10, cookTime: 5, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Ambuyat' },
  { title: 'Nasi Katok', summary: 'Brunei\'s simple fried chicken and rice with sambal', description: 'Nasi Katok is Brunei\'s most popular street food — a packet of steamed rice with a piece of fried chicken and fiery sambal chili sauce, sold everywhere for about $1.', ingredients: ['2 cups jasmine rice, cooked','4 chicken pieces (drumstick or thigh)','1 tsp turmeric','1 tsp salt','oil for frying','For sambal: 10 red chilies','3 shallots','1 clove garlic','1 tbsp shrimp paste','1 tbsp sugar','2 tbsp oil','salt'], instructions: ['Season chicken with turmeric and salt, deep fry until golden and cooked through.','Make sambal: blend chilies, shallots and garlic. Fry in oil with shrimp paste and sugar until dark and fragrant, 10 minutes.','Serve a mound of rice with a piece of fried chicken and a generous spoon of sambal.'], prepTime: 10, cookTime: 20, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Nasi_katok' },
  { title: 'Soto Brunei', summary: 'Bruneian spiced chicken soup with noodles and herbs', description: 'Soto Brunei is a fragrant chicken soup spiced with turmeric and lemongrass, served with rice noodles, bean sprouts, boiled egg and fried shallots.', ingredients: ['500g chicken thighs','2 stalks lemongrass, bruised','2-inch galangal, sliced','1 tsp turmeric','3 shallots, sliced','3 cloves garlic','6 cups water','200g rice vermicelli','bean sprouts','hard-boiled eggs','fried shallots','lime wedges','salt'], instructions: ['Boil chicken in water with lemongrass, galangal, turmeric, shallots and garlic for 30 minutes.','Remove chicken, shred meat, strain broth.','Cook vermicelli noodles according to package, drain.','Assemble bowls: noodles, shredded chicken, bean sprouts.','Ladle hot broth over, top with sliced egg and fried shallots.','Serve with lime wedges and chili sauce.'], prepTime: 15, cookTime: 35, servings: 4, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Soto_(food)' },
  { title: 'Kuih Cincin', summary: 'Bruneian ring-shaped deep-fried rice flour cookies', description: 'Kuih Cincin are traditional Bruneian ring-shaped fritters made from rice flour and sugar, deep-fried until crunchy — a beloved festive treat.', ingredients: ['2 cups rice flour','1/2 cup sugar','1/2 cup coconut milk','1/4 tsp salt','oil for deep frying'], instructions: ['Mix rice flour, sugar, salt and coconut milk into a stiff dough.','Shape small pieces into rings about 2 inches in diameter.','Heat oil to 160°C (320°F).','Fry rings in batches until golden and crispy, about 5 minutes.','Drain on paper towels.','Store in an airtight container — they stay crispy for days.'], prepTime: 15, cookTime: 20, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Kuih_cincin' },
  { title: 'Kuih Mor', summary: 'Bruneian steamed coconut milk cake', description: 'Kuih Mor is a traditional Bruneian steamed cake made with coconut milk, eggs and sugar — soft, fragrant and slightly jiggly.', ingredients: ['1 cup all-purpose flour','1 cup coconut milk','1/2 cup sugar','3 eggs','1/4 tsp salt','1/4 tsp pandan extract'], instructions: ['Whisk eggs and sugar until fluffy.','Add coconut milk, flour, salt and pandan extract, mix until smooth.','Pour into a greased steaming mold.','Steam for 30-35 minutes until set and a toothpick comes out clean.','Cool before unmolding.','Serve at room temperature, sliced.'], prepTime: 10, cookTime: 35, servings: 8, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Bruneian_cuisine' },
  { title: 'Kelupis', summary: 'Bruneian glutinous rice wrapped in nyirik leaves', description: 'Kelupis are parcels of glutinous rice cooked in coconut milk, wrapped in nyirik (palm) leaves and steamed — a traditional Bruneian festive food.', ingredients: ['2 cups glutinous rice, soaked 4 hours','1 cup coconut milk','1/2 tsp salt','nyirik or banana leaves for wrapping','string for tying'], instructions: ['Drain soaked rice, mix with coconut milk and salt.','Cut leaves into rectangles, soften over a flame.','Place 2-3 tablespoons of rice mixture on each leaf.','Fold and tie into neat parcels.','Boil or steam parcels for 2-3 hours until rice is fully cooked and sticky.','Serve with rendang or curry.'], prepTime: 30, cookTime: 180, servings: 8, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Bruneian_cuisine' },
  { title: 'Kuih Bahulu', summary: 'Bruneian mini egg sponge cakes baked in a mold', description: 'Kuih Bahulu are light, fluffy Bruneian egg sponge cakes baked in decorative molds — a staple of Hari Raya celebrations.', ingredients: ['4 eggs','1 cup sugar','1.5 cups all-purpose flour','1/2 tsp vanilla extract','1/4 tsp baking powder'], instructions: ['Beat eggs and sugar on high speed for 10 minutes until very thick and tripled in volume.','Gently fold in flour, baking powder and vanilla.','Grease bahulu molds, fill each 3/4 full.','Bake at 180°C (350°F) for 10-12 minutes until golden and springy.','Remove from molds while warm.','Serve as a snack with tea.'], prepTime: 15, cookTime: 12, servings: 12, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Bahulu' },
  { title: 'Beef Rendang Brunei', summary: 'Bruneian slow-cooked beef in rich coconut and spice paste', description: 'Rendang is a deeply flavored Bruneian dish — beef slowly braised in coconut milk and a complex spice paste until dry-fried and intensely aromatic.', ingredients: ['1 kg beef chuck, cubed','2 cans (800ml) coconut milk','10 dried chilies, soaked','6 shallots','4 cloves garlic','2-inch galangal','2 stalks lemongrass','1 tbsp turmeric','1 tsp coriander','1/2 cup toasted coconut (kerisik)','2 turmeric leaves (optional)','salt and sugar'], instructions: ['Blend chilies, shallots, garlic, galangal, lemongrass, turmeric and coriander into a paste.','Cook the paste in oil until fragrant, about 10 minutes.','Add beef, stir to coat.','Pour in coconut milk, bring to a boil, then reduce to a simmer.','Cook uncovered for 2-3 hours, stirring occasionally, until sauce is almost completely dry.','Add kerisik (toasted coconut), stir.','Continue cooking until the meat is dark, dry-fried and coated in the thick spice paste.','Season with salt and sugar.'], prepTime: 20, cookTime: 180, servings: 6, difficulty: 'hard', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Rendang' },
  { title: 'Satay Brunei', summary: 'Bruneian grilled marinated chicken skewers with peanut sauce', description: 'Bruneian Satay features tender chicken marinated in turmeric and lemongrass, grilled on bamboo skewers and served with a rich peanut dipping sauce.', ingredients: ['500g chicken thigh, cubed','2 stalks lemongrass, minced','1 tsp turmeric','1 tbsp sugar','1 tbsp oil','salt','bamboo skewers, soaked','For sauce: 1 cup roasted peanuts, ground','2 tbsp chili paste','1 tbsp tamarind juice','2 tbsp sugar','1/2 cup water','salt'], instructions: ['Marinate chicken with lemongrass, turmeric, sugar, oil and salt for 2 hours.','Thread onto soaked bamboo skewers.','Grill over charcoal, turning frequently, 8-10 minutes until charred and cooked.','Make peanut sauce: simmer ground peanuts, chili paste, tamarind, sugar and water for 10 minutes.','Serve skewers with warm peanut sauce, cucumber slices and rice cakes.'], prepTime: 130, cookTime: 10, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Satay' },
  { title: 'Pulut Panggang', summary: 'Bruneian grilled glutinous rice parcels with spicy filling', description: 'Pulut Panggang are banana-leaf parcels of glutinous rice filled with a spicy dried shrimp and coconut filling, grilled until fragrant.', ingredients: ['2 cups glutinous rice, cooked in coconut milk','For filling: 1/2 cup dried shrimp, soaked','1/2 cup grated coconut','3 shallots, sliced','2 red chilies','1 tbsp sugar','salt','banana leaves for wrapping'], instructions: ['Blend dried shrimp, shallots and chilies roughly.','Cook the mixture with grated coconut and sugar until dry and fragrant.','Spread glutinous rice on banana leaf pieces, add a line of filling, roll up.','Secure with toothpicks.','Grill over low charcoal heat, turning, for 10 minutes until leaves are charred and rice is fragrant.','Serve warm.'], prepTime: 30, cookTime: 15, servings: 8, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Pulut_panggang' },
  { title: 'Wajid', summary: 'Bruneian glutinous rice cake with palm sugar and coconut', description: 'Wajid is a traditional Bruneian dessert — glutinous rice cooked with coconut milk and dark palm sugar (gula apong), shaped into a dense, sweet cake.', ingredients: ['2 cups glutinous rice, soaked 4 hours','1 cup coconut milk','1/2 cup gula apong (palm sugar) or dark brown sugar','1/4 tsp salt','banana leaf for lining'], instructions: ['Drain rice, steam for 20 minutes until half cooked.','Heat coconut milk with palm sugar and salt until dissolved.','Mix the hot coconut sugar mixture into the steamed rice.','Line a mold with banana leaf, press in the rice mixture firmly.','Steam for another 30-40 minutes until rice is fully cooked and glossy.','Cool, unmold and slice.'], prepTime: 20, cookTime: 60, servings: 8, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Bruneian_cuisine' },
  { title: 'Laksa Brunei', summary: 'Bruneian spicy coconut noodle soup', description: 'Laksa Brunei is a rich, spicy noodle soup with a coconut and tamarind broth, served with rice noodles, chicken, shrimp and fresh herbs.', ingredients: ['200g rice vermicelli','300g chicken breast, shredded','200g shrimp, peeled','3 cups coconut milk','2 cups chicken broth','4 tbsp laksa paste (chilies, lemongrass, galangal, turmeric, shrimp paste)','2 tbsp tamarind juice','bean sprouts','hard-boiled egg','Vietnamese mint','lime wedges'], instructions: ['Cook rice vermicelli, drain.','Fry laksa paste in oil until fragrant, 5 minutes.','Add coconut milk and broth, bring to a simmer.','Add tamarind juice, chicken and shrimp, cook 10 minutes.','Assemble bowls: noodles, ladle soup with chicken and shrimp.','Top with bean sprouts, egg halves and mint.','Serve with lime wedges.'], prepTime: 15, cookTime: 20, servings: 4, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Laksa' },
  { title: 'Nasi Lemak Brunei', summary: 'Bruneian coconut rice with sambal and accompaniments', description: 'Nasi Lemak Brunei is fragrant rice cooked in coconut milk and pandan, served with sambal, fried anchovies, peanuts, cucumber and a boiled egg.', ingredients: ['2 cups jasmine rice','1 cup coconut milk','1 cup water','2 pandan leaves, knotted','1/2 tsp salt','For sambal: 10 dried chilies, 3 shallots, 1 tbsp shrimp paste, 2 tbsp sugar','1/2 cup fried anchovies','1/4 cup roasted peanuts','cucumber slices','4 boiled eggs'], instructions: ['Cook rice with coconut milk, water, pandan leaves and salt.','Make sambal: blend chilies and shallots, fry with shrimp paste and sugar until dark.','Serve rice with sambal, fried anchovies, peanuts, cucumber and egg.'], prepTime: 15, cookTime: 25, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Nasi_lemak' },
  { title: 'Gulai Ikan Brunei', summary: 'Bruneian fish in turmeric coconut curry', description: 'Gulai Ikan is a Bruneian fish curry — firm white fish simmered in a fragrant coconut curry sauce flavored with turmeric, lemongrass and galangal.', ingredients: ['600g firm white fish fillets, cut into pieces','1 can coconut milk','2 stalks lemongrass, bruised','2-inch galangal, sliced','1 tsp turmeric','4 shallots, sliced','2 red chilies','1 tbsp tamarind juice','salt and sugar','fresh cilantro'], instructions: ['Blend shallots, chilies and turmeric into a paste.','Fry paste with lemongrass and galangal until fragrant.','Pour in coconut milk, bring to a simmer.','Add fish pieces, cook gently 10 minutes.','Add tamarind juice, salt and sugar to taste.','Garnish with cilantro, serve with rice.'], prepTime: 10, cookTime: 20, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Gulai' },
  { title: 'Kuih Lapis', summary: 'Bruneian multi-layered steamed rice flour cake', description: 'Kuih Lapis is a colorful Bruneian layered cake — each thin layer of rice flour and coconut milk is steamed one at a time, creating a beautiful striped dessert.', ingredients: ['1.5 cups rice flour','1/2 cup tapioca flour','2 cups coconut milk','1 cup sugar','1/4 tsp salt','food coloring (red, green)','1 tbsp pandan extract'], instructions: ['Mix rice flour, tapioca flour, coconut milk, sugar and salt into a smooth batter.','Divide into 3 portions, color each differently (leave one white, one green/pandan, one red).','Grease a 8-inch square pan.','Pour a thin layer of one color, steam 5 minutes.','Add another color layer, steam 5 minutes.','Repeat alternating colors for 9-12 layers.','Cool completely before unmolding and slicing.'], prepTime: 20, cookTime: 60, servings: 8, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Kuih_lapis' },
  { title: 'Daging Masak Hitam', summary: 'Bruneian beef braised in dark soy sauce', description: 'Daging Masak Hitam is Bruneian braised beef — chunks of beef slow-cooked in dark soy sauce with sweet spices until deeply caramelized and tender.', ingredients: ['500g beef chuck, cubed','3 tbsp dark soy sauce','2 tbsp sugar','4 shallots, sliced','3 cloves garlic, minced','1 cinnamon stick','3 star anise','2 cloves','1 cup water','2 tbsp oil','salt'], instructions: ['Brown beef in oil, remove.','Fry shallots and garlic until golden, add cinnamon, star anise and cloves.','Return beef, add dark soy sauce, sugar and water.','Simmer on low heat 1.5-2 hours until beef is tender and sauce is thick and dark.','Season with salt.','Serve with rice.'], prepTime: 10, cookTime: 120, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Bruneian_cuisine' },
  { title: 'Kuih Apam', summary: 'Bruneian fluffy steamed coconut milk pancakes', description: 'Kuih Apam are small, soft Bruneian steamed cakes made with coconut milk and rice flour — slightly fermented, resulting in a fluffy, spongy texture.', ingredients: ['2 cups rice flour','1 cup coconut milk','1/2 cup sugar','1/2 tsp dry yeast','1/2 cup warm water','pinch of salt','1/4 tsp pandan extract'], instructions: ['Dissolve yeast in warm water.','Mix rice flour, sugar, salt and pandan extract.','Add coconut milk and yeast mixture, stir smooth.','Let batter ferment 3-4 hours until bubbly.','Pour into small greased molds (2/3 full).','Steam for 12-15 minutes until puffed and cooked.','Serve warm.'], prepTime: 15, cookTime: 15, servings: 8, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Apam' },
  { title: 'Mee Goreng Brunei', summary: 'Bruneian stir-fried egg noodles with prawns and vegetables', description: 'Mee Goreng is Brunei\'s version of stir-fried noodles — yellow egg noodles wok-fried with shrimp, vegetables, egg and a sweet-spicy sauce.', ingredients: ['400g yellow egg noodles','200g shrimp, peeled','2 eggs','1 cup cabbage, shredded','1 carrot, julienned','2 tbsp sweet soy sauce (kecap manis)','1 tbsp chili sauce','2 cloves garlic, minced','2 tbsp oil','bean sprouts','lime wedges'], instructions: ['Cook noodles until just tender, drain.','Heat oil in a wok, fry garlic, add shrimp, cook until pink.','Push aside, scramble eggs.','Add cabbage, carrot and bean sprouts, stir-fry 2 minutes.','Add noodles, sweet soy sauce and chili sauce.','Toss everything together on high heat for 2 minutes.','Serve with lime wedges.'], prepTime: 10, cookTime: 10, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Mie_goreng' },
  { title: 'Tauhu Sumbat', summary: 'Bruneian stuffed tofu puffs with vegetable filling', description: 'Tauhu Sumbat are tofu puffs stuffed with a crunchy mixture of shredded vegetables and covered with sweet peanut sauce — a popular Bruneian street snack.', ingredients: ['12 tofu puffs (tau pok)','1 cup bean sprouts','1 cucumber, julienned','1 small jicama, julienned','For peanut sauce: 1/2 cup roasted peanuts, ground','2 tbsp sweet soy sauce','1 tbsp chili paste','1 tbsp lime juice','2 tbsp water','salt'], instructions: ['Cut each tofu puff in half, creating a pocket.','Stuff with bean sprouts, cucumber and jicama.','Make sauce: mix ground peanuts, sweet soy sauce, chili paste, lime juice and water.','Drizzle peanut sauce generously over the stuffed tofu.','Serve immediately as a snack.'], prepTime: 15, cookTime: 0, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Bruneian_cuisine' },
  { title: 'Roti Boyan', summary: 'Bruneian coconut-filled griddled flatbread', description: 'Roti Boyan is a sweet Bruneian flatbread filled with grated coconut and palm sugar, pan-fried until golden — named after the Boyan community.', ingredients: ['2 cups all-purpose flour','1/2 cup water','1 tbsp butter','1/4 tsp salt','For filling: 1 cup grated coconut','1/3 cup palm sugar or brown sugar','1/4 tsp cinnamon','butter for frying'], instructions: ['Make dough: flour, water, butter, salt. Knead smooth, rest 20 minutes.','Mix coconut, palm sugar and cinnamon for filling.','Divide dough into 8 balls, roll each thin.','Place filling on one half, fold over and seal edges.','Fry in butter on a griddle 2-3 minutes per side until golden.','Serve warm as a snack or breakfast.'], prepTime: 20, cookTime: 15, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Bruneian_cuisine' },
],
};
